select C.accentity, C.transType, C.orgId, C.businessID, C.businessDate, C.businessNum, C.businessStatus, C.currency, C.payStatus, C.settleStatus, C.settlemode, C.planProgram, C.ourAccId, C.ourCashAccId, C.paymentType, C.noteId, C.expenseItem, C.oppType, C.oppName, C.oppDocId, C.oppAcc, C.oppAccName, C.oppAccType, C.oppAccOpenName, C.originAmount, C.exchangeRateType, C.remark, C.businessDetailNum, C.sourceBusinessSystem, C.isIntegrateSettlementPlatform, C.serviceCode from (select A.accentity as accentity, A.source_trade_type_id as transType, D.org as orgId, A.id as businessID, D.bill_date as businessDate, A.code as businessNum, case A.verifystate when 0 then 1 when 1 then 2 when 2 then 4 when 3 then 5 else 3 end as businessStatus, D.currency as currency, null as payStatus, case E.settle_status when 1 then 0 when 2 then 1 when 4 then 3 else 2 end as settleStatus, B.settle_method_id as settlemode, B.fund_plan_project_id as planProgram, D.enterprise_bankaccount as ourAccId, B.curr_cash_acct_id as ourCashAccId, B.quick_type_code as paymentType, B.note_id as noteId, B.expense_item_id as expenseItem, case B.eopp_type when 1 then 3 when 3 then 4 when 4 then 9 when 5 then 1 when 6 then 5 else 2 end as oppType, E.opposite_object_name as oppName, E.opposite_object_name as oppDocId, B.opp_bank_acct_no as oppAcc, B.opp_bank_acct_name as oppAccName, B.opp_bank_type_id as oppAccType, B.opp_bank_dot_name as oppAccOpenName, B.nori_amount as originAmount, E.exchange_rate_type as exchangeRateType, E.description as remark, B.id as businessDetailNum, 8 as sourceBusinessSystem, IF(D.settle_flag is not null and D.settle_flag = 1, true, false) as isIntegrateSettlementPlatform, 'ficmp0026' as serviceCode from stwb_settleapply A inner join stwb_settleapply_fund_assistant D on A.id = D.id inner join stwb_apply_detail B on A.id = B.header_id inner join stwb_settleapplydetail_fund_assistant E on B.id = E.id where D.settle_flag=0 or (A.verifystate in (0,1,4)and D.settle_flag=1) union all select A.accentity as accentity, A.source_trade_type_id as transType, D.org as orgId, A.id as businessID, case A.verifystate when 0 then 1 when 1 then 2 when 2 then 4 when 3 then 5 else 3 end as businessStatus, A.code as businessNum, A.verifystate as businessStatus, D.currency as currency, null as payStatus, case E.settle_status when 1 then 0 when 2 then 1 when 4 then 3 else 2 end as settleStatus, B.settle_method_id as settlemode, B.fund_plan_project_id as planProgram, B.curr_bank_acct_id as ourAccId, B.curr_cash_acct_id as ourCashAccId, B.quick_type_code as paymentType, B.note_id as noteId, B.expense_item_id as expenseItem, case B.eopp_type when 1 then 3 when 3 then 4 when 4 then 9 when 5 then 1 when 6 then 5 else 2 end as oppType, E.opposite_object_name as oppName, E.opposite_object_id as oppDocId, B.opp_bank_acct_no as oppAcc, B.opp_bank_acct_name as oppAccName, B.opp_bank_type_id as oppAccType, B.opp_bank_dot_name as oppAccOpenName, B.nori_amount as originAmount, E.exchange_rate_type as exchangeRateType, E.description as remark, B.id as businessDetailNum, 8 as sourceBusinessSystem, IF(D.settle_flag is not null and D.settle_flag = 1, true, false) as isIntegrateSettlementPlatform, 'ficmp0024' as serviceCode from stwb_settleapply A inner join stwb_settleapply_fund_assistant D on A.id = D.id inner join stwb_apply_detail B on A.id = B.header_id inner join stwb_settleapplydetail_fund_assistant E on B.id = E.id where D.settle_flag=0 or (A.verifystate in (0,1,4)and D.settle_flag=1) union all select A.accentity as accentity, A.tradetype as transType, A.org as orgId, A.id as businessID, A.vouchdate as businessDate, A.code as businessNum, case A.verifystate when 0 then 1 when 1 then 2 when 2 then 4 when 3 then 5 else 3 end as businessStatus, A.iCurrencyID as currency, B.tradestatus as payStatus, case E.settle_status when 1 then 0 when 3 then 1 when 6 then 3 else 2 end as settleStatus, A.settlemode, A.fundPlanProject as planProgram, A.payBankAccount as ourAccId, null as ourCashAccId, null as paymentType, null as noteId, A.expenseitem as expenseItem, 9 as oppType, null as oppName, B.personnum as oppDocId, B.crtacc as oppAcc, B.crtaccname as oppAccName, null as oppAccType, B.crtbank as oppAccOpenName, B.amount as originAmount, A.exchangeRateType as exchangeRateType, A.summary as remark, B.id as businessDetailNum, 8 as sourceBusinessSystem, false as isIntegrateSettlementPlatform, 'cmp_salarypaylist' as serviceCode from cmp_salarypay A inner join cmp_salarypay_b B on A.id = B.mainid where A.vouchdate between '2024-05-01 00:00:00' and '2024-05-30 23:59:59' union all select A.accentity as accentity, A.tradetype as transType, null as orgId, A.id as businessID, A.vouchdate as businessDate, A.code as businessNum, case A.verifystate when 0 then 1 when 1 then 2 when 2 then 4 when 3 then 5 else 3 end as businessStatus, A.iCurrencyID as currency, A.paystatus as payStatus, case A.settlestatus when 1 then 0 when 3 then 1 when 6 then 3 else 2 end as settleStatus, A.settlemode, null as planProgram, A.payBankAccount as ourAccId, A.paycashaccount as ourCashAccId, null as paymentType, null as noteId, null as expenseItem, 5 as oppType, null as oppName, A.accentity as oppDocId, IF(A.recbankaccount is not null, A.recbankaccount, A.reccashaccount) as oppAcc, null as oppAccName, null as oppAccType, null as oppAccOpenName, A.oriSum as originAmount, A.exchangeRateType as exchangeRateType, A.description as remark, null as businessDetailNum, 8 as sourceBusinessSystem, IF(A.isSettlement is not null and A.isSettlement = 1, true, false) as isIntegrateSettlementPlatform, 'ficmp0052' as serviceCode from cm_transfer_account A where A.isSettlement=0 or (A.verifystate in (0,1,4)and A.isSettlement=1) union all select A.accentity as accentity, A.tradetype as transType, null as orgId, A.id as businessID, A.vouchdate as businessDate, A.code as businessNum, case A.verifystate when 0 then 1 when 1 then 2 when 2 then 4 when 3 then 5 else 3 end as businessStatus, A.iCurrencyID as currency, A.paystatus as payStatus, case A.settlestatus when 1 then 0 when 3 then 1 when 6 then 3 else 2 end as settleStatus, A.collectsettlemode, null as planProgram, A.recbankaccount as ourAccId, A.reccashaccount as ourCashAccId, null as paymentType, null as noteId, null as expenseItem, 5 as oppType, null as oppName, A.accentity as oppDocId, IF(A.payBankAccount is not null, A.payBankAccount, A.paycashaccount) as oppAcc, null as oppAccName, null as oppAccType, null as oppAccOpenName, A.oriSum as originAmount, A.exchangeRateType as exchangeRateType, A.description as remark, null as businessDetailNum, 8 as sourceBusinessSystem, IF(A.isSettlement is not null and A.isSettlement = 1, true, false) as isIntegrateSettlementPlatform, 'ficmp0052' as serviceCode from cm_transfer_account A where A.isSettlement=0 or (A.verifystate in (0,1,4)and A.isSettlement=1) union all select A.accentity as accentity, A.tradetype as transType, null as orgId, A.id as businessID, A.vouchdate as businessDate, A.code as businessNum, case A.verifystate when 0 then 1 when 1 then 2 when 2 then 4 when 3 then 5 else 3 end as businessStatus, A.currency as currency, null as payStatus, case A.settlestatus when 1 then 0 when 2 then 1 when 4 then 3 else 2 end as settleStatus, A.settlemode, null as planProgram, A.paymenterprisebankaccount as ourAccId, null as ourCashAccId, null as paymentType, null as noteId, null as expenseItem, case A.receivetype when 1 then 3 when 3 then 4 when 4 then 9 when 5 then 1 when 6 then 5 else 2 end as oppType, A.receivename as oppName, A.receivenameid as oppDocId, A.receivebankaccountid as oppAcc, A.receivebankaccountname as oppAccName, null as oppAccType, A.receivebankaddress as oppAccOpenName, A.amount as originAmount, A.currencyexchangeratetype as exchangeRateType, A.description as remark, null as businessDetailNum, 8 as sourceBusinessSystem, true as isIntegrateSettlementPlatform, 'cmp_foreignpayment' as serviceCode from cmp_foreignpayment A) C where C.businessDate between #{beginDate} and #{endDate}
and C.currency = #{currencyId}
and C.transtype in
#{item}
and C.accentity in
#{item}
and C.oppAcc in
#{item}
and
C.isIntegrateSettlementPlatform = #{cashItem.isIntegrateSettlementPlatform}
and C.businessStatus in
#{item}
and C.settleStatus in
#{item}
and C.payStatus in
#{item}
order by #{queryPage.orderFields} #{queryPage.orderType}
limit #{queryPage.pageIndex}, #{queryPage.pageSize}

